import { spawn } from "node:child_process";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import { reapAllDaemons } from "./ensure.js";
function tmpDir(prefix) {
    return path.join(os.tmpdir(), `bitfab-reap-${prefix}-${Date.now()}-${Math.random().toString(36).slice(2)}`);
}
function processIsAlive(pid) {
    try {
        process.kill(pid, 0);
        return true;
    }
    catch (err) {
        return err.code !== "ESRCH";
    }
}
async function waitUntilDead(pid, timeoutMs = 5_000) {
    const deadline = Date.now() + timeoutMs;
    while (Date.now() < deadline) {
        if (!processIsAlive(pid)) {
            return true;
        }
        await new Promise((r) => setTimeout(r, 25));
    }
    return !processIsAlive(pid);
}
/**
 * Spawn a process that masquerades as an orphaned studio daemon: its command
 * line ends in `daemon/main.js <socketPath>`, the two substrings findDaemonPids
 * matches on, but it never binds the socket (it just idles). This is exactly the
 * orphan a socket-steal leaves behind.
 */
function spawnFakeDaemon(dir, socketPath) {
    const mainDir = path.join(dir, "daemon");
    fs.mkdirSync(mainDir, { recursive: true });
    const mainPath = path.join(mainDir, "main.js");
    fs.writeFileSync(mainPath, "setInterval(() => {}, 1000000)\nprocess.on('SIGTERM', () => process.exit(0))\n");
    const child = spawn(process.execPath, [mainPath, socketPath, `${dir}.pid`], {
        detached: true,
        stdio: "ignore",
    });
    child.unref();
    if (child.pid == null) {
        throw new Error("failed to spawn fake daemon");
    }
    return child.pid;
}
describe("reapAllDaemons", () => {
    const dirs = [];
    afterEach(() => {
        for (const dir of dirs) {
            try {
                fs.rmSync(dir, { recursive: true, force: true });
            }
            catch { }
        }
        dirs.length = 0;
    });
    it("reaps orphan daemons found by command line, not just the pidfile pid", async () => {
        const base = tmpDir("orphan");
        dirs.push(base);
        fs.mkdirSync(base, { recursive: true });
        const socketPath = path.join(base, "studio-daemon.sock");
        const pidPath = path.join(base, "studio-daemon.pid");
        // Two daemons from two different install dirs, both bound to one socket.
        const dirA = path.join(base, "installA");
        const dirB = path.join(base, "installB");
        dirs.push(dirA, dirB);
        const orphanPid = spawnFakeDaemon(dirA, socketPath);
        const newestPid = spawnFakeDaemon(dirB, socketPath);
        // The pidfile only names the newest, as in the real leak. The orphan is
        // invisible to a pidfile-only kill.
        fs.writeFileSync(pidPath, `${newestPid}\n`);
        // Give both a moment to actually be running.
        expect(await waitUntilDead(orphanPid, 0)).toBe(false);
        await reapAllDaemons(socketPath, pidPath);
        expect(await waitUntilDead(orphanPid)).toBe(true);
        expect(await waitUntilDead(newestPid)).toBe(true);
        expect(fs.existsSync(pidPath)).toBe(false);
    });
    it("does not touch processes bound to a different socket", async () => {
        const base = tmpDir("scoped");
        dirs.push(base);
        fs.mkdirSync(base, { recursive: true });
        const ourSocket = path.join(base, "ours.sock");
        const otherSocket = path.join(base, "other.sock");
        const otherDir = path.join(base, "other");
        dirs.push(otherDir);
        const otherPid = spawnFakeDaemon(otherDir, otherSocket);
        await reapAllDaemons(ourSocket, path.join(base, "ours.pid"));
        expect(processIsAlive(otherPid)).toBe(true);
        // Clean up the survivor.
        try {
            process.kill(otherPid, "SIGKILL");
        }
        catch { }
    });
    it("does not reap a daemon whose socket merely starts with our socket path", async () => {
        const base = tmpDir("prefix");
        dirs.push(base);
        fs.mkdirSync(base, { recursive: true });
        const ourSocket = path.join(base, "studio-daemon.sock");
        // A different socket whose path has ourSocket as a strict prefix.
        const longerSocket = `${ourSocket}2`;
        const longerDir = path.join(base, "longer");
        dirs.push(longerDir);
        const longerPid = spawnFakeDaemon(longerDir, longerSocket);
        await reapAllDaemons(ourSocket, path.join(base, "studio-daemon.pid"));
        expect(processIsAlive(longerPid)).toBe(true);
        try {
            process.kill(longerPid, "SIGKILL");
        }
        catch { }
    });
});
